const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { ApolloServerPluginLandingPageDisabled } = require('@apollo/server/plugin/disabled');
const { typeDefs } = require('./schema');
const { resolvers } = require('./resolvers');

// Disable introspection in production
const server = new ApolloServer({
  typeDefs,
  resolvers,
  // Disable introspection based on environment
  introspection: process.env.NODE_ENV !== 'production',

  // Disable GraphQL Playground in production
  plugins: [
    process.env.NODE_ENV === 'production'
      ? ApolloServerPluginLandingPageDisabled()
      : ApolloServerPluginLandingPageLocalDefault({ embed: true })
  ],

  // Additional security: Include validation rules
  validationRules: [
    // Add depth limiting to prevent deep queries
    depthLimit(10),
    // Add query complexity analysis
    createComplexityLimitRule(1000)
  ],

  // Format errors to avoid leaking stack traces
  formatError: (formattedError, error) => {
    // Don't expose internal server errors in production
    if (process.env.NODE_ENV === 'production') {
      // Log the full error server-side
      console.error('GraphQL Error:', error);

      // Return generic message to client
      if (formattedError.extensions?.code === 'INTERNAL_SERVER_ERROR') {
        return {
          message: 'An internal error occurred',
          extensions: {
            code: formattedError.extensions.code
          }
        };
      }
    }
    return formattedError;
  }
});

// Start the server
const { url } = await startStandaloneServer(server, {
  listen: { port: 4000 }
});

console.log(`🚀 Server ready at ${url}`);

