const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { ApolloServerPluginUsageReporting } = require('@apollo/server/plugin/usageReporting');
const { typeDefs } = require('./schema');
const { resolvers } = require('./resolvers');

// Store for persisted queries (in production, use Redis or database)
const persistedQueries = new Map();

// Example: Pre-register allowed queries
persistedQueries.set(
  'getUserProfile',
  'query GetUserProfile($id: ID!) { user(id: $id) { id name email } }'
);
persistedQueries.set(
  'listProducts',
  'query ListProducts { products { id name price } }'
);

// Custom plugin to enforce persisted queries only
const persistedQueryOnlyPlugin = {
  async requestDidStart() {
    return {
      async didResolveOperation(requestContext) {
        const { request, operation } = requestContext;

        // Allow introspection in development only
        if (process.env.NODE_ENV !== 'production') {
          return;
        }

        // Check if query is persisted
        const queryId = request.extensions?.persistedQuery?.sha256Hash;

        if (!queryId) {
          throw new Error(
            'Only persisted queries are allowed in production. ' +
            'Please use Apollo Client with automatic persisted queries.'
          );
        }

        // Verify the query hash exists in our allowlist
        const allowedQuery = persistedQueries.get(queryId);
        if (!allowedQuery) {
          console.warn(`Rejected unknown persisted query: ${queryId}`);
          throw new Error('Unknown persisted query');
        }
      }
    };
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: false,
  plugins: [
    persistedQueryOnlyPlugin,
    // Optional: Send metrics to Apollo Studio
    ApolloServerPluginUsageReporting({
      sendVariableValues: { none: true },
      sendHeaders: { none: true }
    })
  ]
});

