const { GraphQLError } = require('graphql');
const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const jwt = require('jsonwebtoken');

// Custom validation rule to block introspection for non-admin users
function NoIntrospectionForPublic(context) {
  return {
    Field(node) {
      // Check if field is an introspection field (__schema, __type)
      if (node.name.value === '__schema' || node.name.value === '__type') {
        const { user } = context;

        // Allow if user is authenticated admin
        if (user && user.roles && user.roles.includes('admin')) {
          return; // Allow introspection for admins
        }

        // Block for everyone else
        throw new GraphQLError(
          'GraphQL introspection is not allowed for public access. ' +
          'Please authenticate with admin credentials.',
          {
            extensions: {
              code: 'FORBIDDEN',
              http: { status: 403 }
            }
          }
        );
      }
    }
  };
}

const server = new ApolloServer({
  typeDefs,
  resolvers,

  // Keep introspection enabled at server level
  introspection: true,

  // Add custom validation rule
  validationRules: [NoIntrospectionForPublic]
});

const { url } = await startStandaloneServer(server, {
  listen: { port: 4000 },

  // Extract user from JWT in Authorization header
  context: async ({ req }) => {
    const token = req.headers.authorization?.replace('Bearer ', '');

    if (!token) {
      return { user: null };
    }

    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      return { user: decoded };
    } catch (error) {
      console.error('JWT verification failed:', error);
      return { user: null };
    }
  }
});

console.log(`🚀 Server ready at ${url}`);

